const existingNames = new Set(
  $input.all()
    .map(i => (i.json && i.json.name ? String(i.json.name).trim().toLowerCase() : ''))
    .filter(Boolean)
);

const samples = [
  {
    name: 'Samsung Galaxy Watch Ultra',
    amazon_url: 'https://www.amazon.com/dp/B0F7Q4L81N?th=1',
    walmart_url: 'https://www.walmart.com/ip/Samsung-Galaxy-Watch-Ultra-47mm-2025-Edition-Bluetooth-Wi-Fi-4GLTE-Smart-Fitness-Watch-International-Version-Titanium-Blue/17452806183',
    track_google_shopping: true,
    target_price: null,
    last_amazon_price: null,
    last_walmart_price: null,
    last_google_min_price: null,
  },
  {
    name: 'Apple Watch Series 11',
    amazon_url: 'https://www.amazon.com/dp/B0FQFL8PZ5?th=1',
    walmart_url: 'https://www.walmart.com/ip/Apple-Watch-Series-11-GPS-Cellular-42mm-Gold-Titanium-Case-with-Gold-Milanese-Loop/17828855921',
    track_google_shopping: true,
    target_price: null,
    last_amazon_price: null,
    last_walmart_price: null,
    last_google_min_price: null,
  },
  {
    name: 'XIAOMI Redmi Watch 5',
    amazon_url: 'https://www.amazon.com/dp/B0DFZPR9Z4?th=1',
    walmart_url: 'https://www.walmart.com/ip/Redmi-Watch-5-Active-Midnight-Black-18-Day-Battery-Life-2-Inch-Display-5ATM-Waterproof-Bluetooth-Calling-Alexa-Built-In/15893513091',
    track_google_shopping: true,
    target_price: null,
    last_amazon_price: null,
    last_walmart_price: null,
    last_google_min_price: null,
  },
];

return samples
  .filter(s => !existingNames.has(s.name.toLowerCase()))
  .map(s => ({ json: s }));

const row = $input.first().json;

const stripQs = (u) => (u || '').split(/[?#]/)[0];
const amazonUrl = stripQs(row.amazon_url);
const walmartUrl = stripQs(row.walmart_url);

const asinMatch = amazonUrl.match(/\/(?:dp|gp\/product)\/([A-Z0-9]{10})/i);
const walmartMatch = walmartUrl.match(/walmart\.com\/ip\/(?:[^/]+\/)?(\d+)/i);

const trackGoogle = row.track_google_shopping === true || row.track_google_shopping === 'true' || row.track_google_shopping === 1;

return [{
  json: {
    id: row.id,
    name: row.name || '',
    amazon_asin: asinMatch ? asinMatch[1].toUpperCase() : '',
    walmart_product_id: walmartMatch ? walmartMatch[1] : '',
    google_query: trackGoogle ? (row.name || '') : '',
    target_price: row.target_price ?? null,
    last_amazon_price: row.last_amazon_price ?? null,
    last_walmart_price: row.last_walmart_price ?? null,
    last_google_min_price: row.last_google_min_price ?? null,
  },
}];

const parsed = $('Extract Product URLs').item.json;

const numOrNull = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const s = typeof v === 'string' ? v.replace(/[^0-9.]/g, '') : v;
  const n = parseFloat(s);
  return Number.isFinite(n) ? n : null;
};

const getBody = (item) => (item && item.response && item.response.body) || (item && item.body) || item;

const readPrice = (nodeName, paths) => {
  try {
    const item = $(nodeName).item.json;
    if (!item) return { price: null, error: null };
    if (item.error) {
      const msg = (item.error && (item.error.message || item.error.description)) || String(item.error);
      return { price: null, error: msg };
    }
    const body = getBody(item);
    for (const path of paths) {
      const parts = path.split('.');
      let cur = body;
      for (const p of parts) cur = cur == null ? cur : cur[p];
      const n = numOrNull(cur);
      if (n !== null) return { price: n, error: null };
    }
    return { price: null, error: null };
  } catch (e) {
    return { price: null, error: e.message };
  }
};

const amazon = readPrice('Amazon Product', ['pricing', 'list_price', 'price']);
const walmart = readPrice('Walmart Product', ['price', 'current_price.price', 'pricing']);

let google = { price: null, error: null };
try {
  const g = $('Scrape Google Shopping Data').item.json;
  if (g && g.error) {
    google.error = (g.error && (g.error.message || g.error.description)) || String(g.error);
  } else if (g) {
    const body = getBody(g);
    const items = body.shopping_results || body.results || [];
    const prices = items
      .map(it => numOrNull(it && (it.extracted_price !== undefined ? it.extracted_price : it.price)))
      .filter(p => p !== null);
    google.price = prices.length ? Math.min(...prices) : null;
  }
} catch (e) {
  google.error = e.message;
}

const ts = new Date().toISOString();
const target = parsed.target_price;

const evaluate = (platform, current, previous, error) => {
  const dropped = current !== null && previous !== null && previous > 0 && current < previous;
  const pct_drop = dropped ? Number((((previous - current) / previous) * 100).toFixed(2)) : 0;
  const crossed_target = Number.isFinite(target) && Number.isFinite(current) && Number.isFinite(previous) && previous > target && current <= target;
  return {
    timestamp: ts,
    product_name: parsed.name,
    platform,
    current_price: current,
    previous_price: previous,
    dropped: dropped || crossed_target,
    pct_drop,
    error: error || '',
  };
};

const results = [];
if (parsed.amazon_asin) results.push(evaluate('amazon', amazon.price, parsed.last_amazon_price, amazon.error));
if (parsed.walmart_product_id) results.push(evaluate('walmart', walmart.price, parsed.last_walmart_price, walmart.error));
if (parsed.google_query) results.push(evaluate('google_shopping', google.price, parsed.last_google_min_price, google.error));

const update = {
  id: parsed.id,
  last_amazon_price: amazon.price !== null ? amazon.price : (parsed.last_amazon_price != null ? parsed.last_amazon_price : null),
  last_walmart_price: walmart.price !== null ? walmart.price : (parsed.last_walmart_price != null ? parsed.last_walmart_price : null),
  last_google_min_price: google.price !== null ? google.price : (parsed.last_google_min_price != null ? parsed.last_google_min_price : null),
};

return [{ json: { results, update } }];

const drops = $input.all().map(i => i.json);
if (drops.length === 0) return [];

drops.sort((a, b) => (b.pct_drop || 0) - (a.pct_drop || 0));

const esc = (s) => String(s == null ? '' : s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const fmt = (n) => n == null || n === '' ? '—' : '$' + Number(n).toFixed(2);

const rowsHtml = drops.map(d => `<tr>
  <td>${esc(d.product_name)}</td>
  <td>${esc(d.platform)}</td>
  <td style="text-align:right;">${fmt(d.previous_price)}</td>
  <td style="text-align:right;color:#0a7d27;font-weight:600;">${fmt(d.current_price)}</td>
  <td style="text-align:right;">${d.pct_drop ? d.pct_drop + '%' : '—'}</td>
</tr>`).join('');

const subject = `Price drop alert — ${drops.length} product${drops.length === 1 ? '' : 's'} dropped today`;
const html = `<div style="font-family:-apple-system,Segoe UI,sans-serif;max-width:680px;">
  <h2 style="margin:0 0 12px;">${subject}</h2>
  <p style="color:#555;margin:0 0 16px;">Fresh prices from Amazon, Walmart, and Google Shopping — collected on autopilot by ScraperAPI.</p>
  <table cellpadding="8" cellspacing="0" style="border-collapse:collapse;width:100%;font-size:14px;">
    <thead><tr style="background:#f4f4f6;text-align:left;">
      <th>Product</th><th>Marketplace</th><th style="text-align:right;">Was</th><th style="text-align:right;">Now</th><th style="text-align:right;">Drop</th>
    </tr></thead>
    <tbody>${rowsHtml}</tbody>
  </table>
</div>`;

return [{ json: { count: drops.length, subject, html } }];
